public class Main {
    public static void main(String[] args) {
        Grader pct = new PercentGrader();
        Grader pf = new PassFailGrader();
        System.out.println("Score 85:");
        System.out.println("  Percent grade: " + pct.grade(85));
        System.out.println("  Pass/Fail:     " + pf.grade(85));
        System.out.println("Score 45:");
        System.out.println("  Percent grade: " + pct.grade(45));
        System.out.println("  Pass/Fail:     " + pf.grade(45));
    }
}

interface Grader {
    String grade(int score);
}

class PercentGrader implements Grader {
    public String grade(int score) {
        if (score >= 90) return "A";
        if (score >= 80) return "B";
        if (score >= 70) return "C";
        if (score >= 60) return "D";
        return "F";
    }
}

class PassFailGrader implements Grader {
    public String grade(int score) {
        return score >= 50 ? "PASS" : "FAIL";
    }
}

public class Main {
    public static void main(String[] args) {
        Grader pct = new PercentGrader();
        Grader pf = new PassFailGrader();
        System.out.println("Score 85:");
        System.out.println("  Percent grade: " + pct.grade(85));
        System.out.println("  Pass/Fail:     " + pf.grade(85));
        System.out.println("Score 45:");
        System.out.println("  Percent grade: " + pct.grade(45));
        System.out.println("  Pass/Fail:     " + pf.grade(45));
    }
}

